{
  "openapi": "3.0.0",
  "paths": {
    "/payments/{paymentId}/process": {
      "post": {
        "summary": "Process a payment",
        "description": "Process the specified payment.",
        "tags": [
          "payments"
        ],
        "parameters": [
          {
            "name": "paymentId",
            "in": "path",
            "description": "Unique identifier for the payment",
            "required": true,
            "schema": {
              "type": "string"
            }
          }
        ],
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "properties": {
                  "amount": {
                    "type": "number",
                    "description": "The amount of the payment in the currency.",
                    "example": 100.00
                  },
                  "currency": {
                    "type": "string",
                    "description": "The currency code for the payment.",
                    "enum": [
                      "USD",
                      "EUR",
                      "GBP",
                      "JPY"
                    ],
                    "example": "USD"
                  },
                  "paymentDetails": {
                    "type": "object",
                    "description": "Payment details",
                    "properties": {
                      "cardNumber": {
                        "type": "string",
                        "description": "Card number",
                        "example": "1234 5678 9012 3456"
                      },
                      "expirationDate": {
                        "type": "string",
                        "format": "date-time",
                        "description": "Expiration date of the card",
                        "example": "2024-03-15T00:00:00Z"
                      },
                      "cvv": {
                        "type": "string",
                        "description": "CVV code",
                        "example": "123"
                      }
                    }
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "Payment processed successfully",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "orderId": {
                      "type": "string",
                      "description": "Unique order identifier"
                    },
                    "status": {
                      "type": "string",
                      "description": "Payment status"
                    }
                  }
                }
              }
            }
          },
          "400": {
            "description": "Invalid payment details"
          },
          "500": {
            "description": "Internal server error"
          }
        }
      }
    }
  }
}
